import { useQuery } from '@tanstack/react-query';
import React, { useEffect } from 'react'
import { useParams } from 'react-router-dom'
import { Img_URL, fetchSearch } from '../../utils/fetchApi';

const Search = () => {
  const {searchTerm} = useParams();


    const {isLoading,isError,error,data:searchItem}=useQuery({
      queryKey:['searchItem'],

      queryFn: ()=> fetchSearch(`${searchTerm}`)
      .then((res)=>{
        console.log(res);
        return res.results;
      }
        ),
    })


  if (isLoading) {
    return (
      <div className="loading">
        <h1>Loading</h1>
      </div>
    );
  } else if (isError) {
    return (
      <div className="error">
        <p>{error.message}</p>
      </div>
    );
  }else{
  return (
    <section className='search'>
      {
        searchItem.map((item)=>(
         <div key={item.id} >
          <h1>{item.title}</h1>
          <aside>
          <img src={item.poster_path && `${Img_URL}${item.poster_path}`} alt="" />
          <p>{item.overview}</p>
          </aside>
        </div>
        ))
      }
    </section>
  )
    }
  }
export default Search
